// Master Orchestrator - Central Health Check & Coordination
// This workflow monitors the health of all sub-workflows
// and provides a daily system status report

const schedule = {
  continuous: [
    { name: '01-Stats Puller', interval: '15 min', critical: true },
    { name: '02-Balance Watchdog', interval: '1 hour', critical: true },
    { name: '03-Smart Bidder', interval: '30 min', critical: true }
  ],
  hourly: [
    { name: '07-Image Factory', interval: '1 hour', critical: false },
    { name: '08-Uploader', interval: '1 hour', critical: false },
    { name: '12-Anomaly Detector', interval: '1 hour', critical: false }
  ],
  periodic: [
    { name: '04-Geo Bidder', interval: 'daily 02:00', critical: false },
    { name: '05-Budget Pacer', interval: '2 hours', critical: true },
    { name: '06-Trend Hunter', interval: '2 hours', critical: false },
    { name: '09-Remoderator', interval: '30 min', critical: false },
    { name: '10-AB Tester', interval: '4 hours', critical: false },
    { name: '15-Position Scanner', interval: '2 hours', critical: false }
  ],
  daily: [
    { name: '11-Daily Report', interval: 'daily 23:55', critical: true },
    { name: '13-Block Optimizer', interval: 'daily 00:10', critical: false },
    { name: '16-Spy Module', interval: 'daily 04:00', critical: false }
  ],
  weekly: [
    { name: '14-Coefficient Tuner', interval: 'weekly Mon 03:00', critical: false },
    { name: '18-Time Optimizer', interval: 'weekly Mon 05:00', critical: false }
  ],
  manual: [
    { name: '17-Campaign Cloner', interval: 'manual trigger', critical: false }
  ]
};

const systemStatus = {
  timestamp: $now.toISO(),
  schedule: schedule,
  total_workflows: 19,
  status: 'operational'
};

return [{ json: systemStatus }];

const status = $('System Status Check').first().json;
const metrics = $('Fetch System Metrics').first().json;

let msg = `🤖 MASTER ORCHESTRATOR - Daily Status\n`;
msg += `${$now.format('dd.MM.yyyy HH:mm')}\n\n`;

msg += `📊 System Status: ${status.status.toUpperCase()}\n`;
msg += `Total workflows: ${status.total_workflows}\n\n`;

msg += `📈 Today's Metrics:\n`;
msg += `  Stats collected: ${metrics.stats_today || 0}\n`;
msg += `  Balance checks: ${metrics.balance_checks_today || 0}\n`;
msg += `  Bid changes: ${metrics.bid_changes_today || 0}\n`;
msg += `  New teasers: ${metrics.new_teasers_today || 0}\n`;
msg += `  Anomalies: ${metrics.anomalies_today || 0}\n`;
msg += `  Balance: $${metrics.last_known_balance || 'N/A'}\n`;
msg += `  Active teasers (7d): ${metrics.active_teasers_week || 0}\n\n`;

msg += `⏰ Schedule Overview:\n`;
msg += `  Critical (always on): ${status.schedule.continuous.length} workflows\n`;
msg += `  Hourly: ${status.schedule.hourly.length} workflows\n`;
msg += `  Periodic: ${status.schedule.periodic.length} workflows\n`;
msg += `  Daily: ${status.schedule.daily.length} workflows\n`;
msg += `  Weekly: ${status.schedule.weekly.length} workflows\n`;
msg += `  Manual: ${status.schedule.manual.length} workflows\n\n`;

msg += `✅ All systems operational`;

return [{ json: { message: msg } }];
